---立绘播放动作
---@class LUIDrawingCtrl
local LUIDrawingCtrl = LxClass("LUIDrawingCtrl", nil)
-----------------------------------------------------------------


---@type LUIEffectObject
local LUIEffectObject = LXImport(".LUIEffectObject")

-----------------------------------------------------------------
function LUIDrawingCtrl:LUIDrawingCtrl()
	---由外部释放obj
	---@type LUIHeroObject
	self._heroObj = nil

	self._effectRoot = nil

	self._drawingTimer = nil

	self._isPlaying = false

	self._nextPlayTime = 0

	self._drawActionData = nil

	---@type table<number,LUIEffectObject>
	self._uiEffObjList = nil

	self._isCalm = false
end

function LUIDrawingCtrl:SetHeroObject(obj)
	self._heroObj = obj
end

function LUIDrawingCtrl:SetEffectInfo(effectRoot, sortBottom , sortUp, scaleSize)
	self._effectRoot = effectRoot
	self._sortBottom = sortBottom
	self._sortUp = sortUp
	self._scaleSize = scaleSize
end

function LUIDrawingCtrl:SetCalmState(bCalm)
	self._isCalm = bCalm
end

function LUIDrawingCtrl:InitHeroEffectInfo(effShowId)
	local drawCd = GameTable.CharacterConfigRef["heroDrawActionCd"] or 3
	local aniEffRef = GameTable.CharacterEffectRef[effShowId]
	local actionData = nil
	local idleAni = nil
	if aniEffRef then
		idleAni = LSpineAniConst.idle
		--local spineName,effectList = self:GetSpineNameAndEffectList(aniEffRef.heroDrawingSpAction)
		--actionData = {spineName = spineName, effectList = effectList, bLoop = false, time = (tonumber(aniEffRef.heroDrawingSpActionTime) or 0) + drawCd}
	end
	self._drawActionData = actionData
	self._drawIdleAni = idleAni
end

function LUIDrawingCtrl:GetSpineNameAndEffectList(ani)
	local spineName,effectList
	if not string.isempty(ani) then
		ani = string.split(ani,"=")
		spineName = ani[1]
		local effectStr = ani[2]
		if not string.isempty(effectStr) then
			effectList = {}
			effectStr = string.split(effectStr,",")
			for i,v in ipairs(effectStr) do
				v = string.split(v,":")
				table.insert(effectList,{uiHierarchy = tonumber(v[2]),effectName = v[1]})
			end
		end
	end
	return spineName,effectList
end

function LUIDrawingCtrl:StartPlay()
	self._isPlaying = true
	self._nextPlayTime = Time.time + 0.3
	self._bNotInit = false

	--- http://192.168.16.2:3002/issues/1168
	if self._heroObj then
		if self._isCalm then
			self._heroObj:PlayCalmAni()
		else
			self._heroObj:SetDrawingIdle(true, self._drawIdleAni)
		end
	end

	if self._drawActionData then
		self:StartDrawingTimer()
	else
		self:ClearDrawingTimer()
	end
end

-----------------------------------------------------------------
function LUIDrawingCtrl:ClearDrawingTimer()
	if self._drawingTimer then
		LxTimer.LoopTimeStop(self._drawingTimer)
		self._drawingTimer = nil
	end
end

function LUIDrawingCtrl:StartDrawingTimer()
	self:ClearDrawingTimer()
	self._drawingTimer = LxTimer.LoopTimeCall(function() self:OnDrawingRun() end, 0)
end
-----------------------------------------------------------------

function LUIDrawingCtrl:OnDrawingRun()
	if not self._isPlaying then return end
	if not self._heroObj then return end
	if not self._heroObj:IsDpValid() then return end

	if self._isCalm then return end

	if not self._isNotInit then
		self._isNotInit = true
		self._heroObj:ResetIdle()
	end



	local time = Time.time
	if time >= self._nextPlayTime then

		self:ClearEffectList()

		local actionData = self._drawActionData
		if not actionData then
			self:ClearDrawingTimer()
			return
		end
		self._isNotInit = true
		local spineName = actionData.spineName
		if not string.isempty(spineName) and self._heroObj:GetDisplaySpine():GetAnimation(spineName) then
			self._heroObj:PlayAni(spineName)
		end
		self._nextPlayTime = time + actionData.time

		self:PrePlayEffect(actionData.effectList)
	end
end

function LUIDrawingCtrl:PrePlayEffect(effectList)
	if not effectList or #effectList == 0 then return end
	local effectObjList = {}
	self._uiEffObjList = effectObjList

	local wndClass = self._heroObj:GetWndClass()

	local sortBottom = self._sortBottom or 0
	local sortUp = self._sortUp or 3
	local scaleSize = self._scaleSize or 100

	local trans = self._effectRoot
	if not trans then
		trans = self._heroObj:GetParentTrans()
	end

	local preloadCount = #effectList
	local onPreloadSkillShow = function()
		if self._isDestroy then return end
		preloadCount = preloadCount - 1
		if preloadCount <= 0 then
			self:PlayUIDrawEffect()
		end
	end

	for i,v in ipairs(effectList) do
		local dp = LUIEffectObject:New(wndClass)
		effectObjList[i] = dp
		local sortIndex = 0
		if tonumber(v.uiHierarchy) == 1 then
			sortIndex = sortBottom
		else
			sortIndex = sortUp
		end
		dp:Create(trans, v.effectName, scaleSize, i, sortIndex,onPreloadSkillShow)
		dp:StartLoad()
	end
end

function LUIDrawingCtrl:PlayUIDrawEffect()
	if self._isDestroy then return end

	local effectObjList = self._uiEffObjList
	if effectObjList and #effectObjList > 0 then
		local time = Time.time
		for i,v in ipairs(effectObjList) do
			v:StartPlay(time,self._nextPlayTime)
			v:OnRun(time)
		end
	end
end

function LUIDrawingCtrl:ClearEffectList()
	for k,v in pairs(self._uiEffObjList or {}) do
		v:Destroy()
	end
	self._uiEffObjList = nil
end


function LUIDrawingCtrl:Destroy()
	self:ClearEffectList()
	self:ClearDrawingTimer()
	table.removeall(self)
	self._isDestroy = true
end
------------------------------------------------------------------
return LUIDrawingCtrl